def show_banner():
    from rich.console import Console
    from rich.panel import Panel
    from rich.text import Text

    console = Console()
    banner = Text()
    banner.append("╔══════════════════════════════════════════╗\n", style="bright_magenta")
    banner.append("║         🔐  C R Y P T O Q U E S T  🔐   ║\n", style="bright_magenta")
    banner.append("║   Cryptography Mastery — Classical to    ║\n", style="magenta")
    banner.append("║         Post-Quantum Cryptography        ║\n", style="magenta")
    banner.append("╚══════════════════════════════════════════╝\n", style="bright_magenta")
    console.print(Panel(banner, border_style="bright_magenta"))


def simulate_boot():
    import time

    from rich.console import Console

    console = Console()
    steps = [
        "[bright_magenta]Loading cryptographic primitives...",
        "[magenta]Initializing AES engine...",
        "[bright_magenta]Generating key material...",
        "[magenta]Mounting cipher suite...",
        "[bright_magenta]CryptoQuest ready. Keys loaded.",
    ]
    for step in steps:
        console.print(step)
        time.sleep(0.2)


def run():
    run_game(
        levels=LEVELS,
        ranks=RANKS,
        colors=COLORS,
        save_file=SAVE_FILE,
        game_name=GAME_NAME,
        show_banner_fn=show_banner,
        simulate_boot_fn=simulate_boot,
        engine=ENGINE,
        achievement_thresholds=ACHIEVEMENTS,
    )


if __name__ == "__main__":
    run()
